insert into public.recipes (slug, title, sl_code, kicker, summary, story, ingredients, steps, dietary, season, section, hero_image, status, sort) values
('inland-cubano', 'The Inland Cubano', 'SL-A01', 'an homage, not a copy', 'Havana''s greatest sandwich, rebuilt with an orchard, a smokehouse, and the cheese from down the road — pressed till it shatters.', 'A real Cuban truck already serves the real thing in this town, and we respect that lane — so this isn''t a Cuban-cuisine concept. It''s a Pacific Northwest sandwich that borrows the Cubano''s soul (mojo pork, the press, la plancha) and swaps the ingredients for the Inland Northwest, one at a time. The mojo gets braised in Green Bluff apple cider. The Swiss becomes WSU''s Cougar Gold — a sharp aged cheddar from the Pullman creamery that tastes like nowhere else (we cut it with a little Gruyère so it still pulls). The mustard turns huckleberry. The soul stays; the place changes. Name it yourself — "Inland Cubano" or "the Spokano" — that vote is the first build-in-public post.', '[{"item": "Pork shoulder", "group": "Cider-mojo pork (batch)", "amount": "4-5 lb"}, {"item": "Orange juice + lime (sour-orange stand-in)", "group": "Cider-mojo pork (batch)", "amount": "3/4 cup + 1/4 cup"}, {"item": "Garlic, smashed", "group": "Cider-mojo pork (batch)", "amount": "8 cloves"}, {"item": "Dried oregano + cumin", "group": "Cider-mojo pork (batch)", "amount": "1 Tbsp + 2 tsp"}, {"item": "Green Bluff apple cider (the braise)", "group": "Cider-mojo pork (batch)", "amount": "1.5 cups"}, {"item": "House hot-smoked pork or local ham", "group": "Build", "amount": "per sandwich"}, {"item": "Cougar Gold + a little Gruyere (melt)", "group": "Build", "amount": "grated"}, {"item": "Huckleberry mustard (Dijon + yellow + mashed huckleberry + honey + cider vinegar)", "group": "Build", "amount": "smear"}, {"item": "Dill pickles + pickled Walla Walla onion", "group": "Build", "amount": "to taste"}, {"item": "Pressed loaf, buttered outside", "group": "Build", "amount": "1"}]'::jsonb, '["Marinate the pork in the mojo 12-24 hours.", "Braise low and covered (300F) in the cider + spent marinade ~4-5 hours, until pull-apart; cool in its juices.", "Whisk the huckleberry mustard; let it sit (holds 2 weeks cold).", "To order: crisp the shredded pork on the flat-top in a little of its own fat.", "Build: mustard, crisped pork, smoked ham, Cougar Gold on both faces (it glues), pickles, pickled onion.", "Butter the outside and press hard 3-4 min/side under a weight until thin, deep golden, shattering, cheese molten.", "Cut on a hard diagonal. (GF: press a GF loaf, or run it as the Inland Cubano Bowl over crispy potatoes.)"]'::jsonb, '{gf-avail}'::text[], NULL, 'anchor', NULL, 'published', 1),
('palouse-falafel', 'The Palouse Falafel', 'SL-A04', 'the dietary hero', 'Crisp falafel from garbanzos grown 80 miles away — tahini, pickled onion, herbs. Naturally gluten-free and vegan, lowest food cost on the menu, biggest local story.', 'Skewers and Jerusalem already make great falafel in Spokane, so we don''t win on novelty — we win on sourcing. Ours is built from Palouse Brand garbanzos, grown by a fifth-generation family farm out of Pullman and cleaned just up the road in Palouse, WA. Same dish, radically different receipts. The one rule that makes or breaks it: dried, soaked, raw garbanzos — never canned, never pre-cooked. Canned falafel falls apart and tastes flat. Soaked-raw fries up shatter-crisp outside, fluffy and green inside. As a bowl it''s natively GF and vegan, which means one item quietly covers most of the dietary market and still costs the least to make. That''s not charity — it''s addressable-market math.', '[{"item": "Palouse Brand dried garbanzos, soaked 18-24h, drained + patted dry", "amount": "2 cups dried"}, {"item": "Onion + garlic", "amount": "1/2 + 3 cloves"}, {"item": "Parsley + cilantro", "amount": "big handfuls"}, {"item": "Cumin + coriander", "amount": "2 tsp + 1 tsp"}, {"item": "Salt + cayenne", "amount": "to taste"}, {"item": "Lemon", "amount": "squeeze"}, {"item": "Chickpea flour (bind) + baking soda (lift)", "amount": "1-2 Tbsp + 1/2 tsp"}, {"item": "Tahini, pickled onion, herbs — to serve", "amount": "—"}]'::jsonb, '["Soak dried garbanzos 18-24 hours (they roughly triple); drain well and pat dry.", "Blitz with onion, garlic, herbs and spices to a coarse, sandy-but-cohesive texture — not a smooth puree.", "Bind with chickpea flour + baking soda; rest 30+ minutes cold.", "Scoop golf-ball portions.", "Fry at 350F until deep brown and shatter-crisp outside, fluffy green inside.", "Serve in a soft pita or as a GF/vegan bowl with tahini, pickled onion, herbs."]'::jsonb, '{gf,vg}'::text[], NULL, 'anchor', NULL, 'published', 2),
('forager-melt', 'The Forager Melt', 'SL-A05', 'the veg anchor, not a consolation', 'Confit foraged mushrooms, Cougar Gold, caramelized onion on griddled local sourdough — the cheese-pull money shot.', 'Most trucks treat the vegetarian option as an apology. This is the opposite: a melt good enough that meat-eaters order it on purpose. Mushrooms get cooked hard — confit or seared until deeply browned, never steamed grey — then folded with onions caramelized low and slow. The cheese is Cougar Gold, sharp and nutty; because aged cheddar melts less stretchily than Swiss, we blend in a little Gruyère so the pull is real. Griddle the local sourdough low and patient until the crust is glass and the cheese is fully molten. In fall it''s foraged chanterelles and the forage itself becomes the content; the rest of the year, cultivated mushrooms done with the same technique.', '[{"item": "Foraged or cultivated mushrooms (chanterelles in fall)", "amount": "big handful per melt"}, {"item": "Butter (or oil for vegan path)", "amount": "to confit"}, {"item": "Thyme + garlic", "amount": "to taste"}, {"item": "Onion, caramelized low + slow", "amount": "1/4 per melt"}, {"item": "Cougar Gold + a little Gruyere (the melt)", "amount": "grated"}, {"item": "Local sourdough", "amount": "2 thick slices"}, {"item": "Herb oil", "amount": "finish"}]'::jsonb, '["Cook the mushrooms hard in butter with thyme + garlic until deeply browned (confit or sear); set aside.", "Caramelize the onion low and slow until jammy.", "Butter the sourdough; griddle low and slow with the cheese blend on both inner faces.", "Layer mushrooms + onion; close and press gently until the cheese is fully molten and the crust is glass.", "Finish with a thread of herb oil. (GF: the same build on GF bread or as a bowl.)"]'::jsonb, '{v,gf-avail}'::text[], NULL, 'anchor', NULL, 'published', 3),
('palouse-smash', 'The Palouse Smash', 'SL-A02', 'The rent-payer', 'An aged-beef smashburger with a lacy, screaming-crust edge, Cougar Gold, and Walla Walla onion jam on a potato bun.', 'Every food business needs one item that quietly pays the rent, and for us that is the smash. The move is borrowed from the diner flat-top tradition and sharpened: aged beef pressed paper-thin onto a screaming-hot surface so the edges go lacy and brown, the Maillard crust doing the heavy lifting that thick patties never deliver. We double-stack for volume and margin, melt Cougar Gold from the WSU Creamery in Pullman over the top, and spoon on a jam of slow-cooked Walla Walla onions. Potato bun, because it is sturdy enough to take the juice without surrendering. This is the burger we build in public: the same beef, the same flat-top temperature, the same eight-minute build, logged shot for shot. Receipts over hype. Want it gluten-free? We run it lettuce-wrapped or as a smash bowl.', '[{"item": "Aged beef (smashed thin, double-stacked)", "amount": ""}, {"item": "Cougar Gold cheese (WSU Creamery, Pullman)", "amount": ""}, {"item": "Walla Walla onion jam", "amount": ""}, {"item": "Potato bun", "amount": ""}, {"item": "Pickles", "amount": ""}]'::jsonb, '["Portion the aged beef into loose balls; do not pack them tight.", "Get the flat-top screaming hot, then smash each ball paper-thin for maximum lacy crust.", "Season, sear hard, and flip once the edges are deep brown.", "Lay Cougar Gold over the patties and let it melt.", "Double-stack the patties so the cheese welds them together.", "Spread Walla Walla onion jam on the toasted potato bun.", "Build the burger, add pickles, and serve hot. GF: lettuce-wrap or smash bowl."]'::jsonb, '{gf-avail}'::text[], NULL, 'anchor', NULL, 'published', 4),
('huck-chicken', 'Huckleberry Hot-Honey Chicken', 'SL-A03', 'Inland sweet-heat-funk', 'Buttermilk-brined fried chicken thigh with a shatter crust, huckleberry hot honey, and pickled Rainier cherries on a potato bun.', 'This is the Inland Northwest folded into a fried-chicken sandwich. The technique we leaned on is the gastrique move, the old French trick of balancing sweet, heat, and acid until none of them shout: huckleberry hot honey for the sweet and the burn, pickled Rainier cherries for the funk and the cut. Underneath is a buttermilk-brined thigh dredged and fried to a true shatter crust at 350F, the kind that cracks audibly on camera. The huckleberry is the heart of it. You cannot farm a wild huckleberry; you forage it, and that forage is a whole content series waiting to happen, every season filmed at the source on the slopes that grow it. Sweet, heat, funk, crunch, on a potato bun that holds the line. We do not pitch this one. We prove it, bite by bite.', '[{"item": "Buttermilk-brined chicken thigh", "amount": ""}, {"item": "Seasoned flour", "amount": ""}, {"item": "Huckleberry hot honey", "amount": ""}, {"item": "Pickled Rainier cherries", "amount": ""}, {"item": "Potato bun", "amount": ""}]'::jsonb, '["Brine the chicken thigh in buttermilk until tender and seasoned through.", "Dredge the thigh in seasoned flour, pressing for a craggy coat.", "Fry at 350F to a deep gold, shatter-crisp crust.", "Drain briefly so the crust stays crackly.", "Drizzle huckleberry hot honey generously over the hot chicken.", "Top with pickled Rainier cherries for funk and acid.", "Build on a toasted potato bun and serve immediately."]'::jsonb, '{gf-avail}'::text[], NULL, 'anchor', NULL, 'published', 5),
('milk-bread', 'The Mother Dough — Milk Bread', 'SL-B01', 'build the bread, rent the rest', 'Tangzhong shokupan: the universal base. One dough becomes split-top rolls, burger buns, a pullman loaf for pressing, and day-olds for bread pudding.', 'The keep-vs-rent rule says build only the edge — and bread is an edge almost no truck bothers with. House-baked bread is the scratch-made flex that defines the best Spokane spots, it''s a cost lever and a quality lever at once, and "we bake our own buns at 5am" is some of the most-watched food content there is. The secret is tangzhong: a cooked flour-and-water paste that pre-gelatinizes the starch so the bread holds more water — cloud-soft crumb, days-longer shelf life. Master this one dough and most of the menu rides on it: griddled split-tops for the rolls, sturdy buns for the smash, a pullman loaf for the Cubano and the melts, and yesterday''s loaf reborn as bread pudding. Nothing wasted. That''s the whole flex.', '[{"item": "Bread flour + water", "group": "Tangzhong", "amount": "20 g + 100 g"}, {"item": "Bread flour", "group": "Dough", "amount": "480 g (incl. tangzhong flour)"}, {"item": "Warm whole milk", "group": "Dough", "amount": "180 g"}, {"item": "Egg", "group": "Dough", "amount": "50 g (1 large)"}, {"item": "Sugar", "group": "Dough", "amount": "50 g"}, {"item": "Instant yeast", "group": "Dough", "amount": "7 g"}, {"item": "Salt", "group": "Dough", "amount": "9 g"}, {"item": "Soft unsalted butter", "group": "Dough", "amount": "50 g"}]'::jsonb, '["Make the tangzhong: whisk flour + water in a pan over medium until it thickens to a pudding paste (~65C); scrape out and cool.", "Mix flour, sugar, yeast, salt; add milk, egg and the cooled tangzhong to a shaggy dough.", "Knead 8-10 min until smooth, then add the soft butter in pieces; knead to silky + windowpane.", "Bulk ferment ~1 hour, until roughly doubled.", "Shape for the use: 8 split-top rolls, 9 burger buns, or 1 pullman loaf.", "Proof 45-60 min until puffy; egg wash.", "Bake 350F (rolls ~16-20 min, loaf ~28-32 min) to deep golden + 195F internal; brush the tops with butter out of the oven.", "Cool fully, then freeze; refresh on the truck. Day-olds become bread pudding."]'::jsonb, '{v}'::text[], NULL, 'dough', NULL, 'published', 4),
('potato-buns', 'Potato Buns', 'SL-B02', 'Pillowy but sturdy', 'A soft potato bun engineered to stay sturdy under a juicy Smash or a saucy fried-chicken sandwich.', 'Every great sandwich starts at the bun, so the Dough Lab started here. We wanted pillowy without flimsy — the bun that cradles a double-stacked Palouse Smash or a shatter-crust Huck Chicken without dissolving into the juices. The borrowed move is mashed potato in the dough: the starch holds moisture, so the crumb stays tender for days while the structure stays tight enough to press and grip. We mix and knead, then work soft butter in until the dough hits a windowpane, bulk an hour, and shape nine-to-ten buns at about 95 grams so every plate matches. That weight is on purpose — a consistent bun is a consistent burger, and consistency is the whole pitch. This is the foundation under two of our anchors, which is why we built it first and show the spec out loud. Cook the season, show the source — even when the source is the bread.', '[{"item": "bread flour", "amount": "500g"}, {"item": "plain mashed potato", "amount": "150g"}, {"item": "warm milk or water", "amount": "~190g"}, {"item": "egg", "amount": "50g"}, {"item": "sugar", "amount": "40g"}, {"item": "instant yeast", "amount": "8g"}, {"item": "salt", "amount": "10g"}, {"item": "soft butter", "amount": "40g"}]'::jsonb, '["Mix the bread flour, mashed potato, warm milk, egg, sugar, yeast and salt into a shaggy dough.", "Knead until smooth and elastic.", "Add the soft butter and knead until it fully works in and the dough passes a windowpane test.", "Bulk ferment about 1 hour until risen.", "Divide and shape into 9-10 buns at about 95g each.", "Proof the buns until puffy.", "Brush with egg wash.", "Bake at 375F for 16-18 minutes until deep golden."]'::jsonb, '{v}'::text[], NULL, 'dough', NULL, 'published', 5),
('cuban-press-bread', 'Cuban-Style Press Bread', 'SL-B03', 'Built to be pressed', 'A thin, crackly-crusted loaf with a soft open crumb, engineered to flatten clean under the press for the Inland Cubano and the melts.', 'The Inland Cubano needs a bread that submits to the press — thin crust that crackles, an open interior soft enough to flatten without fighting back. So we built one. The borrowed move is the lard (or butter) worked into the dough: fat tenderizes the gluten so the loaf stays pliable instead of chewy, which is exactly what you want when a screaming press is crushing it onto cider-braised pork and Cougar Gold. We knead only to medium gluten — tender, not athletic — bulk about an hour, then shape hoagie logs around 250 grams each so every sandwich presses to the same footprint. An optional overnight sponge buys real flavor for the cost of patience. Steam early in the bake sets that crackly skin; the dry finish browns it light golden. This loaf does double duty across the Cubano and every melt on the board, and we publish the gram weights because the receipts are the recipe.', '[{"item": "bread flour", "amount": "500g"}, {"item": "water", "amount": "310g"}, {"item": "lard or butter", "amount": "30g"}, {"item": "sugar", "amount": "15g"}, {"item": "instant yeast", "amount": "7g"}, {"item": "salt", "amount": "10g"}]'::jsonb, '["Optional: build a sponge ahead for deeper flavor.", "Mix the flour, water, lard or butter, sugar, yeast and salt, then knead about 8 minutes to a medium gluten that is tender, not chewy.", "Bulk ferment about 1 hour.", "Shape into hoagie logs at about 250g each.", "Proof about 45 minutes.", "Bake at 400F with steam for 8-10 minutes.", "Vent the steam and finish dry, about 20-22 minutes total, to light golden."]'::jsonb, '{v}'::text[], NULL, 'dough', NULL, 'published', 6),
('focaccia-pizza', 'Focaccia + Pizza Dough', 'SL-B04', 'The preferment doughs', 'One poolish-built dough that goes two ways: airy dimpled focaccia or thin-crust pizza, with deep flavor from a slow cold ferment.', 'This is the dough where patience does the cooking. We start a poolish — equal flour and water with a whisper of yeast — and let it sit 12 to 16 hours until it is bubbly and tangy. That borrowed move, the slow preferment, is the obsessive technique the elevated-pizza spots swear by: it builds flavor and extensibility that no same-day dough can fake. From there it is an autolyse, salt, a few folds to smooth, then a 24-to-72-hour cold ferment that deepens everything further. One base, two outcomes — stretch it into an oiled tray, dimple it, and bake airy focaccia, or ball it, stretch it thin, and fire it as hot as the oven goes for pizza. The focaccia route takes olive oil and stays vegetarian; the lean pizza dough is fully vegan. We log the exact grams and the ferment clock because the long wait is the whole point, and the timeline is the receipt.', '[{"item": "bread flour (poolish)", "group": "poolish", "amount": "150g"}, {"item": "water (poolish)", "group": "poolish", "amount": "150g"}, {"item": "instant yeast (poolish)", "group": "poolish", "amount": "0.4g"}, {"item": "flour", "group": "dough", "amount": "350g"}, {"item": "water", "group": "dough", "amount": "175g"}, {"item": "salt", "group": "dough", "amount": "12g"}, {"item": "instant yeast", "group": "dough", "amount": "3g"}, {"item": "olive oil (focaccia)", "group": "dough", "amount": "25g"}]'::jsonb, '["Whisk the poolish (150g flour, 150g water, 0.4g yeast) and ferment 12-16 hours until bubbly.", "Combine the poolish with the dough flour and water and autolyse 15 minutes.", "Add the salt and fold to a smooth dough.", "Cold ferment 24-72 hours.", "For focaccia: stretch into an oiled tray, dimple, and top.", "Bake focaccia at 450F about 20 minutes.", "For pizza: ball, stretch thin, and bake as hot as the oven goes."]'::jsonb, '{v,vg}'::text[], NULL, 'dough', NULL, 'published', 7),
('socca', 'Socca (GF/Vegan Flatbread)', 'SL-B05', 'No gluten, no compromise', 'A chickpea-flour flatbread with no gluten, dairy, or yeast — crisp-edged, nutty, and the easiest on-brand GF and vegan win on the board.', 'Socca is proof that "gluten-free and vegan" does not have to mean "afterthought." It is a Riviera street food — chickpea flour, water, olive oil, salt — that bakes into a flatbread with crisp lacy edges and a custardy, nutty middle. The borrowed move is the rest: let the batter sit anywhere from 30 minutes to overnight so the garbanzo flour fully hydrates, which is what gives socca its tender bite instead of a chalky one. We lean on Palouse garbanzos from right here in the Palouse, so the most accommodating thing on the menu is also the most local — no gluten, no dairy, no yeast, and the source is 80 miles up the road. The technique is unforgiving in the best way: a cast-iron pan ripping hot at 450F-plus, a thin pour, and patience while the edges crisp. Cumin or rosemary optional. We show the grams and the source because the easy wins still earn their receipts.', '[{"item": "chickpea (garbanzo) flour", "amount": "120g"}, {"item": "water", "amount": "180g"}, {"item": "olive oil", "amount": "2 Tbsp, plus more for the pan"}, {"item": "salt", "amount": "3/4 tsp"}, {"item": "cumin, pepper, or rosemary", "amount": "optional"}]'::jsonb, '["Whisk the chickpea flour, water, olive oil and salt into a smooth, thin batter.", "Stir in optional cumin, pepper or rosemary.", "Rest the batter 30 minutes to overnight to hydrate.", "Heat an oiled cast-iron pan or sheet screaming hot at 450F or higher.", "Pour in a thin layer of batter.", "Cook until set with crisp edges, about 6-10 minutes.", "Cut into wedges and serve."]'::jsonb, '{gf,vg}'::text[], NULL, 'dough', NULL, 'published', 8),
('pita-flatbread', 'Pita / Soft Flatbread', 'SL-B06', 'Pocket or soft, your call', 'One lean dough that bakes into a puffed pocket pita on a hot stone or griddles into a soft flatbread to wrap the Palouse falafel.', 'A falafel is only as good as what holds it, so the Dough Lab built a flatbread that works two ways from one batch. Roll it thin and it does both jobs: slap it on a 500F-plus stone and steam blows it into a pocket, or lay it on a griddle for about a minute a side and it stays soft and foldable. The borrowed move is the puff itself — get the dough thin and the oven hot enough and the trapped steam splits the interior into a clean pocket, no special equipment, just heat and timing. It is a lean, honest dough — flour, water, a little olive oil and sugar — which keeps it fully vegan and lets it wrap the Palouse garbanzo falafel without competing for the spotlight. We portion at about 80 grams a ball so every wrap is the same size, and we publish the grams and the temps because the technique is the product.', '[{"item": "bread flour", "amount": "500g"}, {"item": "water", "amount": "300g"}, {"item": "olive oil", "amount": "15g"}, {"item": "sugar", "amount": "8g"}, {"item": "instant yeast", "amount": "6g"}, {"item": "salt", "amount": "9g"}]'::jsonb, '["Mix the flour, water, olive oil, sugar, yeast and salt into a dough.", "Knead about 8 minutes until smooth.", "Bulk ferment about 1 hour.", "Divide into balls of about 80g each.", "Rest the balls 20 minutes, then roll thin.", "For pocket pita: bake on a 500F+ stone about 3-4 minutes until puffed.", "For soft flatbread: griddle about 1 minute per side."]'::jsonb, '{v,vg}'::text[], NULL, 'dough', NULL, 'published', 9),
('pie-dough', 'All-Butter Pie Dough', 'SL-B08', 'Flake from cold', 'A pate brisee built for hand pies — the elevated Pop-Tart format — where the flake comes from cold butter and barely touching it.', 'The hand pie is our elevated Pop-Tart, and it lives or dies on the pastry. This is a classic all-butter pate brisee, and the borrowed move is the oldest rule in the book: keep everything cold and handle it as little as humanly possible. We cut cold butter into the flour only to pea-to-walnut bits — those visible chunks are the flake, steaming into layers in the oven instead of vanishing into the dough. Ice water goes in just until it holds, then two discs rest cold for at least an hour so the gluten relaxes and the butter firms back up. Roll it cold, fill it, crimp it, egg-wash, vent, and bake to deep golden. It is the same dough under the rhubarb-strawberry, the huckleberry-lavender, and every seasonal hand pie we drop — one foundation, a rotating cast of local fruit. A pinch of sugar tips it toward the sweet pies. We publish the grams because the discipline is the recipe.', '[{"item": "AP flour", "amount": "300g"}, {"item": "cold unsalted butter, cubed", "amount": "225g"}, {"item": "ice water", "amount": "90-110g"}, {"item": "salt", "amount": "6g"}, {"item": "sugar (sweet pies)", "amount": "8g"}]'::jsonb, '["Cut the cold cubed butter into the flour, salt and optional sugar until the bits are pea-to-walnut sized.", "Add ice water just until the dough holds together.", "Form 2 discs and rest cold at least 1 hour.", "Roll the dough out while still cold.", "Cut, fill, and crimp into hand pies.", "Egg wash and cut vents.", "Bake at 400F to deep golden."]'::jsonb, '{v}'::text[], NULL, 'dough', NULL, 'published', 10),
('cake-doughnut', 'Cake Doughnut (Cider)', 'SL-B09', 'Sturdy enough to torch', 'A sturdy cider cake doughnut built to hold a cider-caramel dip and a torched brulee lid without falling apart.', 'Most cake doughnuts go soft and surrender. Ours is engineered to take a beating — specifically the cider-caramel dip and the shattering brulee lid that turn it into the Bruleed Green Bluff Apple-Cider Donut. The borrowed move is reducing apple cider down hard, roughly four-to-one, until it is a syrup that packs orchard flavor into the crumb without watering down the batter. We mix a soft, sticky dough, then chill it 30 minutes so it firms up enough to roll and cut clean rings. A 350F fry for about 90 seconds a side gives a deep-gold crust with enough backbone to survive a torch. The cider points straight at Green Bluff, the cluster of orchards just north of Spokane, so the season is literally in the dough. This is the doughnut base under our marquee fall sweet, and we show the reduction ratio and the fry temp because the technique is what holds the lid.', '[{"item": "reduced apple cider (boiled ~4:1)", "amount": "as needed"}, {"item": "buttermilk", "amount": "as needed"}, {"item": "egg", "amount": "1"}, {"item": "melted butter", "amount": "as needed"}, {"item": "vanilla", "amount": "to taste"}, {"item": "AP flour", "amount": "as needed"}, {"item": "sugar", "amount": "as needed"}, {"item": "baking powder", "amount": "as needed"}, {"item": "salt", "amount": "pinch"}, {"item": "cinnamon", "amount": "to taste"}, {"item": "nutmeg", "amount": "to taste"}]'::jsonb, '["Boil apple cider down to about a 4:1 reduction and cool.", "Combine the reduced cider, buttermilk, egg, melted butter and vanilla.", "Mix in the flour, sugar, baking powder, salt, cinnamon and nutmeg to a soft, sticky dough.", "Chill the dough 30 minutes.", "Roll to about 1/2 inch and cut rings.", "Fry at 350F about 90 seconds per side to deep gold.", "Dip the tops in cider caramel.", "Torch a sugar crust over the top."]'::jsonb, '{v}'::text[], NULL, 'dough', NULL, 'published', 11),
('spot-prawn-roll', 'Spot Prawn Roll', 'SL-D01', 'Three weekends only', 'Butter-poached spot prawns dressed with brown butter, lemon, and chive, piled on a griddled split-top milk-bread roll.', 'Spot prawns are the sweetest thing the coast makes, and the window is brutally short. Washington spot shrimp open around late May, the season runs maybe three weekends, it is not every area every year, and then they are gone. That scarcity is the whole story, and we film it in real time at the source. The borrowed move is butter-poaching, the precise lobster-roll discipline where the line between perfect and rubber is measured in seconds: peel the prawns, slip them into a glossy beurre monte, and pull them the instant they turn. We dress with brown butter, a hit of Meyer or yuzu lemon, snipped chive, and flaky salt, then pile them onto a split-top griddled in butter until the edges crisp. No filler, no sauce to hide behind. When it is this good and this brief, you do not pitch it. You prove it, and you move fast. GF on request.', '[{"item": "Spot prawns", "amount": ""}, {"item": "Beurre monte", "amount": ""}, {"item": "Meyer or yuzu lemon", "amount": ""}, {"item": "Snipped chive", "amount": ""}, {"item": "Flaky salt", "amount": ""}, {"item": "Milk-bread split-top roll", "amount": ""}, {"item": "Butter (for griddling)", "amount": ""}]'::jsonb, '["Peel the spot prawns.", "Poach them very briefly in beurre monte, or sear about 60 seconds, until just opaque.", "Pull them the instant they turn so they stay sweet, not rubbery.", "Dress with brown butter, Meyer or yuzu lemon, and snipped chive.", "Finish with flaky salt.", "Griddle a split-top milk-bread roll in butter until the edges crisp.", "Pile the prawns into the roll and serve right away."]'::jsonb, '{gf-avail}'::text[], 'Spring', 'drop', NULL, 'published', 1),
('morel-nettle-toast', 'Morel & Nettle Cream Toast', 'SL-D09', 'Forest floor in May', 'Hard-seared morels in a quick cream pan sauce over nettle-hazelnut pesto on thick griddled milk bread.', 'This is the forest floor in May, on toast. Both stars are foraged, not farmed: morels that push up after the spring thaw and stinging nettles that have to be blanched before they will behave. The borrowed move is the classic French mushroom sauce, morels seared hard so they brown instead of steam, deglazed with a splash of sherry or white wine, then finished with just enough cream to coat. Under it we lay a nettle pesto, the nettles blanched thirty seconds to kill the sting, then blitzed with garlic, toasted hazelnuts, oil, lemon, and a hard cheese. Everything stacks on thick milk bread griddled until golden. Foraging is the build-in-public gift: every morel and every nettle filmed at the source, the season itself the content. Cook the season, show the source. Vegetarian as built, GF on request.', '[{"item": "Morels (cleaned)", "amount": ""}, {"item": "Butter", "amount": ""}, {"item": "Sherry or white wine", "amount": "a splash"}, {"item": "Cream", "amount": ""}, {"item": "Nettles (blanched 30s)", "amount": ""}, {"item": "Garlic", "amount": ""}, {"item": "Hazelnuts", "amount": ""}, {"item": "Lemon", "amount": ""}, {"item": "Hard cheese", "amount": ""}, {"item": "Thick milk bread", "amount": ""}]'::jsonb, '["Saute the cleaned morels hard in butter until deeply browned.", "Deglaze with a splash of sherry or white wine.", "Add a little cream and reduce to a coating sauce.", "Blanch the nettles for 30 seconds to tame the sting.", "Blitz the nettles with garlic, toasted hazelnuts, oil, lemon, and hard cheese into a pesto.", "Griddle thick milk bread until golden.", "Spread the nettle pesto on the toast, spoon the creamy morels over, and finish with lemon."]'::jsonb, '{v,gf-avail}'::text[], 'Spring', 'drop', NULL, 'published', 2),
('dungeness-roll', 'Dungeness Roll', 'SL-D06', 'The summer halo', 'Sweet, just-picked Dungeness piled on a buttered, griddled split-top — the premium drop we price like the photo magnet it is.', 'Every menu needs one item that stops the thumb-scroll, and in summer that''s the Dungeness Roll. We borrowed the lobster-roll discipline — restraint over mayonnaise overload — and pointed it at Washington''s best crab. The whole move is gentleness: pick the crab, keep the lumps intact, dress it just enough with lemon aioli or brown butter, and let the meat be the loudest thing in the room. The split-top milk bread gets griddled in butter until the cut faces go gold and crisp, a frame that holds without competing. We price this one high on purpose and show why — the crab cost, the yield from picking, the labor — because building in public means the receipts ride alongside the plate. It''s the premium halo that makes the rest of the board look honest. Cook the season, show the source.', '[{"item": "Picked Dungeness crab", "amount": "keep the lumps whole"}, {"item": "Lemon aioli or brown butter", "amount": "to dress"}, {"item": "Snipped chive", "amount": "to finish"}, {"item": "Milk-bread split-top bun", "amount": "1, buttered + griddled"}, {"item": "Lemon", "amount": "to finish"}]'::jsonb, '["Pick the Dungeness carefully, keeping the lumps as whole as possible.", "Gently dress the crab with lemon aioli or warm brown butter — just enough to coat.", "Butter the cut faces of the split-top milk-bread bun.", "Griddle the bun cut-side down until gold and crisp.", "Pile the dressed crab generously into the warm bun.", "Finish with a squeeze of lemon and snipped chive.", "Serve immediately while the bun is still hot."]'::jsonb, '{gf-avail}'::text[], 'Summer', 'drop', NULL, 'published', 3),
('dungeness-corn-fritters', 'Dungeness & Sweet Corn Fritters', 'SL-D05', 'Two WA legends, fried', 'Fresh summer corn and picked Dungeness battered into deep-gold cakes, fried to order and served three-up on orchard slaw with lemon aioli.', 'This is the fritter we make when we want to brag about Washington without saying a word. Two things the state does better than almost anywhere — sweet summer corn and Dungeness crab — fried into one deep-gold cake. The borrowed move is the corn-fritter playbook from Gulf Coast crab shacks, but we lighten the batter with a flour-and-cornstarch blend so it shatters instead of clumps, and we fold the crab in last to keep the lumps proud. An Old-Bay-leaning seasoning ties it together; lemon aioli cuts the richness; an orchard slaw underneath keeps it bright. We batter to order, every time, because a fritter that sat is a fritter that lied — and on the line that discipline is the receipt. Served three to a plate, it eats like a summer celebration. Cook the season, show the source.', '[{"item": "Fresh sweet corn kernels", "amount": "cut from the cob"}, {"item": "Flour + cornstarch blend", "amount": "for the batter"}, {"item": "Egg", "amount": "1"}, {"item": "Green onion", "amount": "sliced"}, {"item": "Old-Bay-ish seasoning", "amount": "to taste"}, {"item": "Picked Dungeness crab", "amount": "keep the lumps"}, {"item": "Lemon aioli", "amount": "to serve"}, {"item": "Orchard slaw", "amount": "to serve underneath"}]'::jsonb, '["Whisk together the corn kernels, flour-cornstarch blend, egg, green onion, and Old-Bay-ish seasoning into a batter.", "Gently fold in the picked Dungeness, keeping the lumps intact.", "Heat oil to 350F.", "Drop small cakes into the oil and fry until deep gold.", "Drain the fritters on a rack.", "Plate a bed of orchard slaw.", "Set three fritters on the slaw with lemon aioli.", "Batter to order — never hold the mix."]'::jsonb, '{gf-avail}'::text[], 'Summer', 'drop', NULL, 'published', 4),
('grilled-peach-pork', 'Grilled Peach + Smoked Pork', 'SL-D13', 'Summer on a bun', 'Charred Green Bluff peach, smoked pork, and huckleberry hot honey stacked on a potato bun — August in one handful.', 'Around August the Green Bluff orchards hit their peach peak, and that window is the whole reason this sandwich exists. The borrowed move is grilling stone fruit cut-side down — char concentrates the sugar and gives you a savory edge that plays against smoked pork like it was always meant to. We warm the pork (hot-smoked or cider-braised, depending on the day''s prep), then build on a potato bun with the grilled peach, a lashing of huckleberry hot honey for sweet-heat-funk, pickled onion for the acid snap, and arugula or slaw to keep it from getting heavy. It''s a drop, not a fixture — when Green Bluff''s peaches are done, so is this — and saying so out loud is the point. We cook the season and show exactly which orchard it came from. Summer on a bun, gone with the harvest.', '[{"item": "Ripe peach halves", "amount": "Green Bluff, in season ~Aug"}, {"item": "Hot-smoked or cider-braised pork", "amount": "warmed"}, {"item": "Huckleberry hot honey", "amount": "to drizzle"}, {"item": "Pickled onion", "amount": "to top"}, {"item": "Arugula or slaw", "amount": "a handful"}, {"item": "Potato bun", "amount": "1"}]'::jsonb, '["Halve and pit ripe Green Bluff peaches.", "Grill the peach halves cut-side down to char and sweeten.", "Warm the smoked or cider-braised pork.", "Toast or warm the potato bun.", "Layer the pork onto the bun.", "Add the grilled peach and drizzle with huckleberry hot honey.", "Top with pickled onion and a handful of arugula or slaw.", "Close and serve while warm."]'::jsonb, '{gf-avail}'::text[], 'Summer', 'drop', NULL, 'published', 5),
('wild-mushroom-lentil-bowl', 'Wild Mushroom & Palouse Lentil Bowl', 'SL-D17', 'The whole region in a bowl', 'Foraged fall mushrooms piled over lentils grown 80 miles away, finished with herb oil and your choice of cheese or toasted hazelnuts.', 'This is the dish that makes the case for the whole region without saying a word. The lentils come from Palouse Brand, grown in the rolling dryland just outside Pullman, maybe 80 miles from the kitchen. The mushrooms come from the fall forest floor: chanterelles and matsutake, foraged when the rains hit. We braise the lentils tender but never mushy, the way you would treat good beans, then sear the mushrooms hard in a confit-then-blast move borrowed from steakhouse line cooks so they get color instead of steam. Some get folded into the lentils to thicken the body; the rest pile on top so the eater sees exactly what they paid for. It is naturally gluten-free and goes vegan with a swap to hazelnuts and lemon instead of hard cheese. We show the source because we can. Cook the season, show the source.', '[{"item": "Palouse Brand lentils", "amount": ""}, {"item": "mirepoix (onion, carrot, celery)", "amount": ""}, {"item": "fresh thyme", "amount": ""}, {"item": "stock", "amount": ""}, {"item": "chanterelles or matsutake", "amount": ""}, {"item": "herb oil", "amount": ""}, {"item": "hard cheese OR toasted hazelnuts + lemon (vegan)", "amount": ""}, {"item": "jammy egg", "amount": "optional"}]'::jsonb, '["Braise the Palouse Brand lentils with mirepoix, thyme and stock until tender but still holding their shape, not mushy.", "Clean the mushrooms well and confit or sear them hard so they take on deep color rather than steaming.", "Fold a portion of the mushrooms into the braised lentils to build body.", "Pile the remaining mushrooms on top so the eater can see what they paid for.", "Finish with a drizzle of herb oil.", "For the standard build, grate over hard cheese; for vegan, scatter toasted hazelnuts and a squeeze of lemon.", "Crown with a jammy egg if you want it."]'::jsonb, '{gf,v,vg-avail}'::text[], 'Fall', 'drop', NULL, 'published', 6),
('cider-braised-pork-apple-melt', 'Cider-Braised Pork + Apple Melt', 'SL-D18', 'The Cubano gone autumn', 'Cider-braised pork, thin-sautéed Green Bluff apple and Cougar Gold pressed on house bread, with a side of jus for dipping.', 'Nothing in this kitchen gets cooked once. The pork in this melt is the exact same cider braise that anchors our Inland Cubano, repurposed instead of re-made, which is how a small operation keeps margin honest. Here it goes full autumn. We sauté thin slices of Green Bluff apple just until they slump, layer them with the shredded pork and a sharp blanket of Cougar Gold from the WSU Creamery in Pullman, then press the whole thing on our own house bread until the crust crackles and the cheese pulls. The borrowed move is the French dip: we serve a cup of the braising jus on the side so you can dunk every bite back into the liquid it came from. Green Bluff apples land in fall, the cider braise is already on the line, and the receipts add up. Waste less, prove more.', '[{"item": "cider-braised pork", "amount": ""}, {"item": "Green Bluff apple, thin-sautéed", "amount": ""}, {"item": "Cougar Gold", "amount": ""}, {"item": "house bread", "amount": ""}, {"item": "whole-grain or huckleberry mustard", "amount": ""}, {"item": "braising jus", "amount": ""}]'::jsonb, '["Warm the cider-braised pork in a little of its own jus.", "Sauté thin slices of Green Bluff apple until just softened and lightly colored.", "Spread whole-grain or huckleberry mustard on the house bread.", "Layer pork, sautéed apple and Cougar Gold between the slices.", "Press the sandwich until the crust is crackly and the cheese melts.", "Slice and serve with a side cup of the braising jus for dipping, French-dip style."]'::jsonb, '{gf-avail}'::text[], 'Fall', 'drop', NULL, 'published', 7),
('razor-clam-slider', 'Crispy Razor Clam Slider', 'SL-D02', 'Crunchy, briny, gone fast', 'Razor clams dredged in panko and cornmeal, flash-fried to gold, on a slider bun with remoulade, lettuce and pickle.', 'The razor clam is a Pacific Northwest birthright, and the only honest way to serve it is to respect both the dig and the fry. Razor-clam digs are state-regulated, opened on specific tides after the toxin tests clear, so we source legally and on the calendar, never off a back channel. That sourcing discipline is the whole point: receipts first. In the kitchen the technique is restraint. We dredge the cleaned clams flour, then egg, then a panko-and-cornmeal coat that gives the shatter and the grit you want, and we flash-fry at 350F for about 90 seconds, just to gold. Any longer and a razor clam turns to a rubber band. We stack it on a slider bun with a bright remoulade, shredded lettuce and a sharp pickle. It is the PNW classic done right: crunchy, briny, and gone before the next batch hits the oil.', '[{"item": "razor clams", "amount": ""}, {"item": "flour", "amount": ""}, {"item": "egg", "amount": ""}, {"item": "panko + cornmeal", "amount": ""}, {"item": "slider bun", "amount": ""}, {"item": "remoulade", "amount": ""}, {"item": "shredded lettuce", "amount": ""}, {"item": "pickle", "amount": ""}]'::jsonb, '["Source razor clams legally on an open, state-regulated dig and clean them thoroughly.", "Set up a dredging station: flour, beaten egg, then a mix of panko and cornmeal.", "Coat each clam flour to egg to the panko-cornmeal crust.", "Flash-fry at 350F for about 90 seconds, just until gold; do not overcook or they turn rubbery.", "Drain briefly on a rack.", "Spread remoulade on a slider bun.", "Build with the fried clam, shredded lettuce and a pickle, and serve immediately."]'::jsonb, '{}'::text[], 'Fall', 'drop', NULL, 'published', 8),
('penn-cove-mussels', 'Penn Cove Mussels, Cider-Cream', 'SL-D07', 'Feels like thirty dollars', 'Whidbey Island mussels steamed in Green Bluff cider with shallot, garlic and thyme, finished with cream and butter, grilled bread to mop.', 'This is the cheapest dish on the board that eats like the most expensive, and that gap is the whole story. Penn Cove mussels come off ropes in the cold water of Whidbey Island, farmed cleanly and sustainably, which means we can pour them on generously without flinching at the cost. We steam them open in Green Bluff cider with shallot, garlic and thyme, then finish the broth the French way: a little cream and a knob of cold butter swirled in off the heat to monté it into something glossy and rich. A shower of parsley, a few slices of grilled house bread to mop the bowl, and you have a plate that feels like a thirty-dollar entrée built from humble parts. Whidbey water, Green Bluff orchard, our own bread. We tell you exactly where every piece comes from, because that is the point.', '[{"item": "Penn Cove mussels", "amount": ""}, {"item": "Green Bluff cider", "amount": ""}, {"item": "shallot", "amount": ""}, {"item": "garlic", "amount": ""}, {"item": "thyme", "amount": ""}, {"item": "cream", "amount": ""}, {"item": "butter", "amount": ""}, {"item": "parsley", "amount": ""}, {"item": "grilled house bread", "amount": ""}]'::jsonb, '["Clean and debeard the Penn Cove mussels, discarding any that won''t close.", "Sweat shallot and garlic, then add Green Bluff cider and thyme and bring to a simmer.", "Add the mussels, cover, and steam just until they open.", "Lift out the mussels and discard any that stayed shut.", "Finish the broth off the heat with a splash of cream and a knob of cold butter, swirling to monté.", "Pour the broth over the mussels and shower with parsley.", "Serve with grilled house bread for mopping."]'::jsonb, '{gf-avail}'::text[], 'Winter', 'drop', NULL, 'published', 9),
('cougar-gold-french-dip', 'Cougar Gold + Palouse Onion French Dip', 'SL-D08', 'Soup you can hold', 'Deeply caramelized onions, thin-sliced braised beef and Cougar Gold pressed on house bread, served with a cup of rich beef-onion jus to dip.', 'French onion soup is one of the great slow dishes, and we wanted to put it in your hand. The borrowed move is obvious once you taste it: take everything that makes the soup, the deeply caramelized onions cooked 45 to 60 minutes until they go mahogany, the rich beef broth, the blanket of melted cheese, and rebuild it as a sandwich you dip back into the soup. The cheese is Cougar Gold, the cellar-aged sharp white from the WSU Creamery in Pullman, a Washington icon that melts into something nutty and serious. We layer it with thin-sliced braised beef on our own house bread and press it until the edges crisp. Then the French-dip payoff: a cup of the rich beef-and-onion jus alongside, so every bite goes back into the liquid. Slow onions, local cheese, our bread. Cook the season, show the source.', '[{"item": "onions, deeply caramelized (45-60 min)", "amount": ""}, {"item": "thin-sliced braised beef", "amount": ""}, {"item": "Cougar Gold", "amount": ""}, {"item": "house bread", "amount": ""}, {"item": "rich beef + onion jus", "amount": ""}]'::jsonb, '["Caramelize the onions low and slow for 45 to 60 minutes until deep mahogany.", "Build a rich beef-and-onion jus for dipping.", "Warm the thin-sliced braised beef.", "Layer beef, caramelized onions and Cougar Gold on the house bread.", "Press the sandwich until the edges crisp and the cheese melts.", "Slice and serve with a cup of the hot jus to dip back into."]'::jsonb, '{gf-avail}'::text[], 'Winter', 'drop', NULL, 'published', 10),
('rhubarb-strawberry-hand-pie', 'Rhubarb-Strawberry Hand Pie', 'SL-S10', 'First pie of the year', 'Spring''s first pie: tart rhubarb and early strawberry, jammy inside an all-butter Pop-Tart crust, gone by June.', 'Every season opens with a pie, and rhubarb is the gun going off. It''s the first thing that pushes up tart and red while the rest of the menu is still waking up, so we lean into the scarcity: tart, jammy, gone by June. The borrowed move is the Pop-Tart format, taken seriously instead of ironically — our all-butter pie dough cut into hand-held rectangles, where the flake comes from cold butter and barely touching the thing. Early strawberries balance the rhubarb''s sour edge; a little lemon and cornstarch tighten the filling so it doesn''t weep through the crimp. We cook the filling down and cool it before it ever meets dough, because a hot fill is a soggy bottom. Build-in-public angle: the produce dates the post. When the rhubarb''s done, the pie''s done, and the receipts say so.', '[{"item": "Rhubarb, sliced", "amount": ""}, {"item": "Early strawberries, hulled and quartered", "amount": ""}, {"item": "Sugar", "amount": ""}, {"item": "Cornstarch", "amount": ""}, {"item": "Lemon", "amount": ""}, {"item": "Salt", "amount": "pinch"}, {"item": "All-butter pie dough", "amount": ""}]'::jsonb, '["Cook the rhubarb and strawberry with sugar, lemon, and a pinch of salt until softened.", "Stir in cornstarch and cook briefly to thicken; cool completely.", "Roll the cold all-butter dough and cut into Pop-Tart rectangles.", "Spoon cooled filling onto half the rectangles, leaving a clean border.", "Top, seal, and crimp the edges with a fork.", "Egg wash the tops and cut a vent.", "Bake at 400F until deep golden.", "Drizzle a thin glaze if you like, then cool slightly before serving."]'::jsonb, '{v}'::text[], 'Spring', 'sweet', NULL, 'published', 1),
('marionberry-swirl', 'The Marionberry Swirl', 'SL-S03', 'Berry season, swirled', 'Soft-serve custard rippled with marionberry compote, the fruit rotating weekly so the flavor changes but the line never does.', 'Summer berries don''t hold still, so neither does this. The Marionberry Swirl is a soft-serve custard base with a real fruit compote rippled through it — and the fruit rotates weekly, which is the whole point. Marionberry one week, blackberry the next, whatever''s peaking at the orchards after that. The flavor changes; the line doesn''t. That weekly rotation is a built-in content beat: every swap is a post, every post dates itself by what''s ripe. The borrowed move is the ripple, not a blend — you fold the compote in loosely so each pull shows the marble, which is the photo and the flavor in one. A sorbet base swaps in to make it vegan without losing the swirl. We test it by scooping gelato before the soft-serve machine is on the line, so the recipe is proven before it''s plated. Cook the season, show the source.', '[{"item": "Soft-serve custard base", "amount": ""}, {"item": "Marionberry or blackberry compote (rotate weekly)", "amount": ""}, {"item": "Sorbet base (for the vegan version)", "amount": ""}]'::jsonb, '["Make the soft-serve custard base and chill it down.", "Cook a marionberry or blackberry compote and cool it.", "Ripple the compote loosely through the base so it marbles, not blends.", "Run it through the soft-serve machine (or scoop gelato to test).", "Pull each serving so the swirl shows.", "Rotate the fruit weekly as berries peak.", "For vegan, build the same swirl on a sorbet base.", "Serve immediately while soft."]'::jsonb, '{v,vg-avail}'::text[], 'Summer', 'sweet', NULL, 'published', 2),
('bruleed-cider-donut', 'Bruleed Green Bluff Apple-Cider Donut', 'SL-S02', 'Torched orchard lid', 'An orchard cake donut built on reduced cider, dipped in cider caramel, and torched into a shattering brulee crust.', 'Green Bluff is the orchard belt just north of Spokane, and fall there smells like cider before it smells like anything else. This donut puts that smell on a plate. We start with a cake doughnut batter built on cider that''s been boiled down hard, so the apple flavor is concentrated, not watered into the crumb. Then the borrowed move: the brulee. Instead of a sugar toss or a glaze, we dip the tops in cider caramel and torch a sugar crust into a lid that shatters when you bite it — the unbeatable shot, the reason this thing films itself. It''s the same caramel that runs through the bread pudding, so nothing gets made twice. Build-in-public angle: the torch is the content. You hear the crack, you see the steam, you know exactly where the cider came from. Cook the season, show the source.', '[{"item": "Cake-doughnut batter built on reduced cider", "amount": ""}, {"item": "Cider caramel", "amount": ""}, {"item": "Sugar (for the brulee crust)", "amount": ""}]'::jsonb, '["Fry the cake donut to deep gold.", "Cool slightly so the surface sets.", "Dip the tops in cider caramel.", "Sprinkle an even layer of sugar over the caramel.", "Torch the sugar into a shattering brulee lid.", "Let the crust set hard for a few seconds, then serve."]'::jsonb, '{v}'::text[], 'Fall', 'sweet', NULL, 'published', 3),
('house-bread-pudding', 'House Bread Pudding', 'SL-S11', 'Nothing wasted', 'Yesterday''s house milk bread soaked in vanilla custard, baked warm and golden, finished with cider caramel or a torched top.', 'The Dough Lab bakes milk bread every day, and day-old loaves are not garbage — they''re tomorrow''s dessert. This bread pudding is our zero-waste move made delicious: yesterday''s house milk bread, cubed and soaked in a real vanilla custard of egg, cream, and sugar, then baked until the center sets and the top goes golden. The borrowed finish is a choice — cider caramel poured warm, or a torched sugar lid that ties it back to the bruleed donut. Either way it reuses what the kitchen already makes, which is exactly the point. In a build-in-public food shop, zero-waste isn''t a slogan, it''s a receipt: you can see the loaf it came from and the date it was baked. Warm, custardy, restrained on the sweetness so the bread still tastes like bread. Nothing wasted, everything shown.', '[{"item": "Day-old house milk bread, cubed", "amount": ""}, {"item": "Egg", "amount": ""}, {"item": "Cream or milk", "amount": ""}, {"item": "Sugar", "amount": ""}, {"item": "Vanilla", "amount": ""}, {"item": "Cider caramel or sugar for a bruleed top", "amount": ""}]'::jsonb, '["Cube the day-old house milk bread.", "Whisk a vanilla custard of egg, cream or milk, and sugar.", "Soak the cubes in the custard until saturated.", "Transfer to a baking dish and bake until set and golden.", "Serve warm.", "Finish with cider caramel, or torch a sugar crust on top."]'::jsonb, '{v,gf-avail}'::text[], 'Winter', 'sweet', NULL, 'published', 4),
('huck-lavender-pie', 'Huckleberry-Lavender Hand Pie', 'SL-S01', 'The fixed sweet', 'All-butter hand pie packed with huckleberries and a restrained whisper of lavender, the one sweet that never leaves the menu.', 'Most of our sweets rotate with what''s ripe, but this one stays — the fixed sweet, the anchor on a board full of drops. Huckleberry is the Inland Northwest''s signature wild fruit, and the forage behind it is a whole content series on its own. Here it goes into an all-butter hand pie in the Pop-Tart format, where the flake comes from cold butter and minimal handling, the same dough discipline as every other pie we cut. The borrowed move is restraint: lavender is easy to overdo into soap, so we use a deliberately small pinch, just enough to lift the berry without taking it over. We cook the filling and cool it before it touches dough so the crimp seals clean and the bottom stays crisp. Because it''s always on, it''s the one people learn to trust — and trust is the whole brand. We don''t pitch. We prove.', '[{"item": "Huckleberries", "amount": ""}, {"item": "Sugar", "amount": ""}, {"item": "Cornstarch", "amount": ""}, {"item": "Lemon", "amount": ""}, {"item": "Lavender", "amount": "restrained pinch"}, {"item": "All-butter pie dough", "amount": ""}]'::jsonb, '["Cook the huckleberries with sugar, lemon, and a restrained pinch of lavender.", "Stir in cornstarch to thicken, then cool completely.", "Roll the cold all-butter dough and cut into hand-pie rectangles.", "Spoon cooled filling onto half the rectangles, leaving a border.", "Top, seal, and crimp the edges.", "Egg wash and cut a vent.", "Bake at 400F to golden, then cool slightly."]'::jsonb, '{v}'::text[], NULL, 'sweet', NULL, 'published', 5),
('affogato', 'The Affogato', 'SL-S04', 'Espresso meets swirl', 'A shot of local-roaster espresso pulled over a scoop of the swirl — a thirty-second build that drinks like a dessert and a coffee at once.', 'The affogato is the easiest premium move on the menu and the smartest. It''s a scoop of the Marionberry Swirl soft-serve with a shot of local-roaster espresso pulled straight over the top, served the second it hits. Thirty seconds to build, a premium feel, and a fat margin — the kind of math that pays for the slower dishes. The borrowed move is Italian and old: hot espresso melting cold cream into a drink-it-or-spoon-it hybrid, where the bitterness of the coffee cuts the sweetness of the swirl. The local angle does double duty — partnering with a Spokane roaster turns a dessert into a collab, which is a post for them and a post for us. Because the swirl rotates with the season, the affogato quietly changes too, no new recipe required. Build-in-public made simple: name the roaster, show the pull, let the steam sell it.', '[{"item": "A scoop of the swirl (soft-serve)", "amount": "1 scoop"}, {"item": "Local-roaster espresso", "amount": "1 shot"}]'::jsonb, '["Scoop the swirl soft-serve into a serving cup.", "Pull a fresh shot of local-roaster espresso.", "Pour the espresso over the swirl.", "Serve immediately while the contrast is hot and cold."]'::jsonb, '{v}'::text[], NULL, 'sweet', NULL, 'published', 6)
