-- 0013_recipes_seed.sql — version-controlled seed of the 29 live recipes.
-- Idempotent: re-running upserts by slug. Generated from project zaskrhtcadamiutdecgu.
-- Mirrors public.recipes created in 0012_recipes.sql.
on conflict (slug) do update set
  title=excluded.title, sl_code=excluded.sl_code, kicker=excluded.kicker, summary=excluded.summary,
  story=excluded.story, ingredients=excluded.ingredients, steps=excluded.steps, dietary=excluded.dietary,
  season=excluded.season, section=excluded.section, hero_image=excluded.hero_image, status=excluded.status, sort=excluded.sort;
